import XCTest@testable import MovieQuizfinal class MoviesLoaderTests: XCTestCase {        func testSuccessLoading() throws {        let stubClient = StubNetworkClient(emulateError: false)        let loader = MoviesLoader(networkClient: stubClient)        let expectation = self.expectation(description: "Loading expectation")                loader.loadMovies { result in            switch result {            case .success(let movies):                XCTAssertEqual(movies.items.count, 2)            case .failure:                XCTFail("Expected success")            }            expectation.fulfill()        }        waitForExpectations(timeout: 1)    }        func testFailureLoading() throws {        let stubClient = StubNetworkClient(emulateError: true)        let loader = MoviesLoader(networkClient: stubClient)        let expectation = self.expectation(description: "Loading expectation")                loader.loadMovies { result in            switch result {            case .success:                XCTFail("Expected failure")            case .failure(let error):                XCTAssertNotNil(error)            }            expectation.fulfill()        }        waitForExpectations(timeout: 1)    }}// MARK: - StubNetworkClientfinal class StubNetworkClient: NetworkClientProtocol {        enum TestError: Error { case test }        private let emulateError: Bool        init(emulateError: Bool) {        self.emulateError = emulateError    }        func fetch(url: URL, handler: @escaping (Result<Data, Error>) -> Void) {        if emulateError {            handler(.failure(TestError.test))            return        }        handler(.success(expectedResponse))    }        private var expectedResponse: Data {        """        {            "errorMessage": "",            "items": [                {"fullTitle": "Film 1", "imDbRating": "7.5", "image": "https://example.com/1.jpg"},                {"fullTitle": "Film 2", "imDbRating": "8.0", "image": "https://example.com/2.jpg"}            ]        }        """.data(using: .utf8)!    }}